1	<!DOCTYPE html>
2	<html lang="en">
3	<head>
4	<meta charset="utf-8">
5	<title>Freelance OS — Metric Tuning Console</title>
6	<style>
7	*{box-sizing:border-box;margin:0;padding:0}
8	body{font-family:monospace;font-size:13px;background:#1a1a1a;color:#d8dee9;padding:8px}
9	h2{font-size:13px;color:#88c0d0;border-bottom:1px solid #3b4252;padding-bottom:3px;margin-bottom:6px}
10	h3{font-size:11px;color:#81a1c1;margin:8px 0 3px;text-transform:uppercase;letter-spacing:.5px}
11	.toolbar{display:flex;align-items:center;gap:8px;padding:6px 0 8px;border-bottom:1px solid #3b4252;margin-bottom:8px;flex-wrap:wrap}
12	.grid{display:grid;grid-template-columns:360px 1fr;gap:10px;align-items:start}
13	.panel{background:#242933;border:1px solid #3b4252;padding:8px;border-radius:3px;margin-bottom:8px}
14	table{width:100%;border-collapse:collapse;font-size:12px}
15	th{background:#2e3440;color:#88c0d0;text-align:left;padding:3px 5px;font-size:11px;position:sticky;top:0}
16	td{padding:2px 5px;border-bottom:1px solid #2e3440;white-space:nowrap}
17	tr:hover td{background:#2e3440}
18	.up{color:#a3be8c}
19	.dn{color:#bf616a}
20	.changed td{background:#2d2f24!important}
21	.badge{display:inline-block;padding:0 5px;border-radius:3px;font-size:10px;font-weight:bold}
22	.bd{background:#a3be8c;color:#1a1a1a}.bw{background:#ebcb8b;color:#1a1a1a}
23	.bm{background:#d08770;color:#1a1a1a}.br{background:#bf616a;color:#e0e0e0}
24	.param-row{display:flex;align-items:center;gap:4px;margin-bottom:3px}
25	.param-row label{width:190px;font-size:11px;color:#8090a0;flex-shrink:0}
26	input[type=range]{flex:1;min-width:60px;accent-color:#88c0d0}
27	input[type=number]{width:64px;background:#2e3440;color:#d8dee9;border:1px solid #4c566a;padding:2px 3px;font-size:12px;border-radius:2px}
28	button{background:#3b4252;color:#d8dee9;border:1px solid #4c566a;padding:3px 10px;cursor:pointer;font-size:12px;border-radius:2px}
29	button:hover{background:#4c566a;border-color:#88c0d0}
30	button.primary{background:#4c7899;border-color:#88c0d0}
31	button.save-btn{background:#4a6741;border-color:#a3be8c}
32	select{background:#2e3440;color:#d8dee9;border:1px solid #4c566a;padding:3px 5px;font-size:12px;border-radius:2px}
33	#statusMsg{color:#ebcb8b;font-size:11px}
34	.weight-sum-ok{color:#a3be8c}.weight-sum-bad{color:#bf616a}
35	code{background:#2e3440;padding:1px 4px;border-radius:2px;font-size:11px}
36	.section-head{color:#81a1c1;font-size:11px;font-weight:bold;margin:6px 0 2px;padding:2px 0;border-bottom:1px solid #3b4252}
37	#markersPanel{display:none}
38	#noLeads{color:#6a7482;font-size:12px;padding:20px;text-align:center}
39	.marker-grid{display:grid;grid-template-columns:1fr 1fr;gap:8px}
40	.overflow-x{overflow-x:auto}
41	</style>
42	</head>
43	<body>
44	
45	<div class="toolbar">
46	  <strong style="color:#88c0d0;font-size:14px">Freelance OS — Metric Tuning Console</strong>
47	  <button class="primary" onclick="rescore()" title="Re-score all leads with current params">&#9654; Re-score</button>
48	  <button class="save-btn" onclick="saveConfig()" title="Write params to scoring_rules.toml">&#128190; Save</button>
49	  <select id="presetSelect"><option value="">— load preset —</option></select>
50	  <button onclick="loadPreset()">Load Preset</button>
51	  <button onclick="savePreset()">Save Preset As…</button>
52	  <label style="color:#6a7482;font-size:11px">auto-rescore: <input type="checkbox" id="autoRescore" checked></label>
53	  <span id="statusMsg"></span>
54	</div>
55	
56	<div class="grid">
57	  <!-- LEFT: parameters -->
58	  <div>
59	    <div class="panel">
60	      <h2>Decision Thresholds</h2>
61	      <div id="thresholdsPanel"></div>
62	    </div>
63	    <div class="panel">
64	      <h2>Component Weights &nbsp;<span id="weightSum" class="weight-sum-ok">100</span></h2>
65	      <p style="font-size:10px;color:#5a6374;margin-bottom:4px">Target sum = 100. Each slider is 0–50.</p>
66	      <div id="weightsPanel"></div>
67	    </div>
68	    <div class="panel">
69	      <h2>Risk Penalties</h2>
70	      <div id="penaltiesPanel"></div>
71	    </div>
72	    <div class="panel">
73	      <h2>Pricing Parameters</h2>
74	      <div id="pricingPanel"></div>
75	    </div>
76	  </div>
77	
78	  <!-- RIGHT: markers -->
79	  <div>
80	    <div id="noLeads" class="panel">
81	      No leads in database yet.<br>Add leads with <code>freelance-os lead add-text</code>, then score with <code>freelance-os lead score --all-new</code>.
82	    </div>
83	    <div id="markersPanel">
84	      <div class="panel">
85	        <h2>Aggregate Markers</h2>
86	        <div class="marker-grid">
87	          <div>
88	            <h3>Stats (before → after)</h3>
89	            <table id="statsTable">
90	              <thead><tr><th>Metric</th><th>Before</th><th>After</th><th>Δ</th></tr></thead>
91	              <tbody></tbody>
92	            </table>
93	            <h3>Decision Distribution</h3>
94	            <table id="distTable">
95	              <thead><tr><th>Bucket</th><th>Before</th><th>After</th><th>Δ</th></tr></thead>
96	              <tbody></tbody>
97	            </table>
98	          </div>
99	          <div>
100	            <h3>Calibration — Win Rate by Decision Bucket</h3>
101	            <p style="font-size:10px;color:#5a6374;margin-bottom:4px">Do DRAFT_NOW leads actually win? Requires recorded outcomes.</p>
102	            <table id="calTable">
103	              <thead><tr><th>Decision</th><th>Outcomes</th><th>Win% Before</th><th>Win% After</th></tr></thead>
104	              <tbody></tbody>
105	            </table>
106	            <h3>Top Reason Codes (new scoring)</h3>
107	            <table id="codesTable">
108	              <thead><tr><th>Code</th><th>Count</th></tr></thead>
109	              <tbody></tbody>
110	            </table>
111	          </div>
112	        </div>
113	      </div>
114	
115	      <div class="panel">
116	        <h2>Decision Changes — <span id="changedCount">0</span> leads flipped</h2>
117	        <div class="overflow-x">
118	        <table id="changesTable">
119	          <thead><tr><th>ID</th><th>Title</th><th>Old</th><th>New</th><th>Δ Score</th><th>Outcome</th></tr></thead>
120	          <tbody></tbody>
121	        </table>
122	        </div>
123	      </div>
124	
125	      <div class="panel">
126	        <h2>All Leads — per-lead old vs new</h2>
127	        <div class="overflow-x">
128	        <table id="leadsTable">
129	          <thead><tr>
130	            <th>ID</th><th>Title</th>
131	            <th>Old Score</th><th>New Score</th><th>Δ</th>
132	            <th>Old Decision</th><th>New Decision</th><th>Changed?</th>
133	            <th>Outcome</th><th>Reason Codes</th>
134	          </tr></thead>
135	          <tbody></tbody>
136	        </table>
137	        </div>
138	      </div>
139	    </div>
140	  </div>
141	</div>
142	
143	<script>
144	"use strict";
145	let currentConfig = {};
146	let rescoreTimer = null;
147	
148	function badge(d) {
149	  const map = {DRAFT_NOW:'bd',WATCH:'bw',MAYBE:'bm',REJECT:'br'};
150	  return d ? `<span class="badge ${map[d]||'br'}">${d}</span>` : '';
151	}
152	
153	function paramRow(key, val, min, max, step, label, unit) {
154	  const id = 'p_' + key;
155	  const u = unit ? ` <span style="color:#5a6374;font-size:10px">${unit}</span>` : '';
156	  return `<div class="param-row">
157	    <label for="${id}_n">${label}${u}</label>
158	    <input type="range" id="${id}" min="${min}" max="${max}" step="${step}" value="${val}"
159	      oninput="syncNum('${id}');scheduleRescore()">
160	    <input type="number" id="${id}_n" min="${min}" max="${max}" step="${step}" value="${val}"
161	      oninput="syncRange('${id}');scheduleRescore()">
162	  </div>`;
163	}
164	
165	function syncNum(id) {
166	  const r = document.getElementById(id);
167	  const n = document.getElementById(id+'_n');
168	  if (r && n) n.value = r.value;
169	  updateWeightSum();
170	}
171	
172	function syncRange(id) {
173	  const r = document.getElementById(id);
174	  const n = document.getElementById(id+'_n');
175	  if (r && n) r.value = n.value;
176	  updateWeightSum();
177	}
178	
179	function updateWeightSum() {
180	  const keys = Object.keys((currentConfig.weights)||{});
181	  let sum = 0;
182	  for (const k of keys) {
183	    const el = document.getElementById('p_weights__'+k+'_n');
184	    if (el) sum += parseFloat(el.value)||0;
185	  }
186	  const el = document.getElementById('weightSum');
187	  if (el) {
188	    el.textContent = Math.round(sum*10)/10;
189	    el.className = Math.abs(sum-100) <= 1 ? 'weight-sum-ok' : 'weight-sum-bad';
190	  }
191	}
192	
193	function renderParams(cfg) {
194	  const t = cfg.thresholds||{};
195	  document.getElementById('thresholdsPanel').innerHTML =
196	    paramRow('thresholds__draft_now_min', t.draft_now_min??80, 50, 100, 1, 'DRAFT_NOW minimum', 'score')
197	   +paramRow('thresholds__watch_min',     t.watch_min??65,     0, 100, 1, 'WATCH minimum', 'score')
198	   +paramRow('thresholds__maybe_min',     t.maybe_min??50,     0, 100, 1, 'MAYBE minimum', 'score');
199	
200	  const w = cfg.weights||{};
201	  document.getElementById('weightsPanel').innerHTML = Object.entries(w)
202	    .map(([k,v]) => paramRow('weights__'+k, v, 0, 50, 1, k.replace(/_/g,' '), 'pts'))
203	    .join('');
204	
205	  const rp = cfg.risk_penalties||{};
206	  document.getElementById('penaltiesPanel').innerHTML = Object.entries(rp)
207	    .map(([k,v]) => paramRow('penalties__'+k, v, 0, 50, 1, k.replace(/_/g,' '), 'pts'))
208	    .join('');
209	
210	  const p = cfg.pricing||{};
211	  document.getElementById('pricingPanel').innerHTML =
212	    paramRow('pricing__target_hourly_rate',    p.target_hourly_rate??75,    10, 500,  5,    'Target hourly rate', '$')
213	   +paramRow('pricing__minimum_project_value', p.minimum_project_value??300, 0, 10000,50,   'Minimum project value', '$')
214	   +paramRow('pricing__risk_multiplier_low',   p.risk_multiplier_low??1.0,  0.5, 3,  0.05, 'Risk multiplier (low)', 'x')
215	   +paramRow('pricing__risk_multiplier_medium',p.risk_multiplier_medium??1.25,0.5,3, 0.05, 'Risk multiplier (medium)', 'x')
216	   +paramRow('pricing__risk_multiplier_high',  p.risk_multiplier_high??1.5, 0.5, 3,  0.05, 'Risk multiplier (high)', 'x')
217	   +paramRow('pricing__rush_multiplier',       p.rush_multiplier??1.25,     1,   3,  0.05, 'Rush multiplier', 'x')
218	   +paramRow('pricing__platform_fee_buffer',   p.platform_fee_buffer??0.10, 0,  0.5, 0.01, 'Platform fee buffer', 'frac');
219	
220	  updateWeightSum();
221	}
222	
223	function collectParams() {
224	  const params = {weights:{}, risk_penalties:{}, thresholds:{}, pricing:{}};
225	  document.querySelectorAll('[id^="p_"][id$="_n"]').forEach(el => {
226	    const key = el.id.replace(/^p_/, '').replace(/_n$/, '');
227	    const [sect, ...rest] = key.split('__');
228	    const k = rest.join('__');
229	    const v = parseFloat(el.value);
230	    const sectMap = {weights:'weights', penalties:'risk_penalties', thresholds:'thresholds', pricing:'pricing'};
231	    const s = sectMap[sect];
232	    if (s) params[s][k] = v;
233	  });
234	  return params;
235	}
236	
237	function scheduleRescore() {
238	  if (!document.getElementById('autoRescore').checked) return;
239	  clearTimeout(rescoreTimer);
240	  rescoreTimer = setTimeout(rescore, 600);
241	}
242	
243	async function rescore() {
244	  clearTimeout(rescoreTimer);
245	  const params = collectParams();
246	  setStatus('Scoring…');
247	  try {
248	    const resp = await fetch('/api/preview', {
249	      method:'POST', headers:{'Content-Type':'application/json'},
250	      body: JSON.stringify(params)
251	    });
252	    if (!resp.ok) { setStatus('Error: ' + await resp.text()); return; }
253	    const data = await resp.json();
254	    renderMarkers(data);
255	    setStatus(`✓ ${data.leads.length} leads scored. ${data.markers.changed_decision_count} decisions changed.`);
256	  } catch(e) { setStatus('Error: '+e.message); }
257	}
258	
259	function renderMarkers(data) {
260	  const m = data.markers;
261	  const hasLeads = data.leads.length > 0;
262	  document.getElementById('noLeads').style.display = hasLeads ? 'none' : '';
263	  document.getElementById('markersPanel').style.display = hasLeads ? '' : 'none';
264	  if (!hasLeads) return;
265	
266	  // Stats
267	  const statsBody = document.querySelector('#statsTable tbody');
268	  const d_avg = m.avg_score_after - m.avg_score_before;
269	  const d_med = m.median_score_after - m.median_score_before;
270	  statsBody.innerHTML = `
271	    <tr><td>Avg score</td><td>${m.avg_score_before.toFixed(1)}</td><td>${m.avg_score_after.toFixed(1)}</td>
272	        <td class="${d_avg>=0?'up':'dn'}">${d_avg>=0?'+':''}${d_avg.toFixed(1)}</td></tr>
273	    <tr><td>Median score</td><td>${m.median_score_before.toFixed(1)}</td><td>${m.median_score_after.toFixed(1)}</td>
274	        <td class="${d_med>=0?'up':'dn'}">${d_med>=0?'+':''}${d_med.toFixed(1)}</td></tr>
275	    <tr><td>Total leads</td><td colspan="3">${data.leads.length}</td></tr>
276	    <tr><td>Decision changes</td><td colspan="3" style="color:#ebcb8b"><b>${m.changed_decision_count}</b></td></tr>`;
277	
278	  // Distribution
279	  const decisions = ['DRAFT_NOW','WATCH','MAYBE','REJECT'];
280	  const distBody = document.querySelector('#distTable tbody');
281	  distBody.innerHTML = decisions.map(d => {
282	    const b = m.distribution_before[d]||0;
283	    const a = m.distribution_after[d]||0;
284	    const dlt = a-b;
285	    return `<tr><td>${badge(d)}</td><td>${b}</td><td>${a}</td>
286	            <td class="${dlt>0?'up':dlt<0?'dn':''}">${dlt>0?'+':''}${dlt}</td></tr>`;
287	  }).join('');
288	
289	  // Calibration
290	  const calBody = document.querySelector('#calTable tbody');
291	  calBody.innerHTML = decisions.map(d => {
292	    const cnt = m.outcome_count_by_decision_before[d]||0;
293	    const wb = m.win_rate_by_decision_before[d];
294	    const wa = m.win_rate_by_decision_after[d];
295	    return `<tr><td>${badge(d)}</td><td>${cnt}</td>
296	            <td>${wb!=null?(wb*100).toFixed(0)+'%':'n/a'}</td>
297	            <td>${wa!=null?(wa*100).toFixed(0)+'%':'n/a'}</td></tr>`;
298	  }).join('');
299	
300	  // Top codes
301	  const codesBody = document.querySelector('#codesTable tbody');
302	  codesBody.innerHTML = (m.top_reason_codes||[]).map(([code,cnt]) =>
303	    `<tr><td><code>${code}</code></td><td>${cnt}</td></tr>`).join('');
304	
305	  // Changed decisions
306	  document.getElementById('changedCount').textContent = m.changed_decision_count;
307	  const changed = data.leads.filter(l => l.decision_changed);
308	  document.querySelector('#changesTable tbody').innerHTML = changed.map(l => {
309	    const dlt = l.delta;
310	    return `<tr><td>${l.id}</td><td title="${l.title}">${l.title.substring(0,35)}</td>
311	            <td>${badge(l.old_decision)}</td><td>${badge(l.new_decision)}</td>
312	            <td class="${dlt>=0?'up':'dn'}">${dlt>=0?'+':''}${dlt}</td>
313	            <td style="font-size:10px">${l.outcome||''}</td></tr>`;
314	  }).join('');
315	
316	  // All leads
317	  const leadsBody = document.querySelector('#leadsTable tbody');
318	  leadsBody.innerHTML = data.leads.map(l => {
319	    const dlt = l.delta;
320	    const cls = l.decision_changed ? 'changed' : '';
321	    const oldScoreStr = l.old_score !== null ? l.old_score : '<span style="color:#5a6374">unsco.</span>';
322	    return `<tr class="${cls}">
323	      <td>${l.id}</td>
324	      <td title="${l.title}">${l.title.substring(0,32)}</td>
325	      <td>${oldScoreStr}</td>
326	      <td><b>${l.new_score}</b></td>
327	      <td class="${dlt>0?'up':dlt<0?'dn':''}">${dlt>0?'+':''}${dlt}</td>
328	      <td>${badge(l.old_decision)}</td>
329	      <td>${badge(l.new_decision)}</td>
330	      <td>${l.decision_changed?'<span style="color:#ebcb8b">&#9654;</span>':''}</td>
331	      <td style="font-size:10px">${l.outcome||''}</td>
332	      <td style="font-size:10px;color:#6a7482">${(l.reason_codes||[]).join(' ')}</td>
333	    </tr>`;
334	  }).join('');
335	}
336	
337	async function saveConfig() {
338	  const params = collectParams();
339	  setStatus('Saving…');
340	  try {
341	    const resp = await fetch('/api/save', {
342	      method:'POST', headers:{'Content-Type':'application/json'},
343	      body: JSON.stringify(params)
344	    });
345	    if (!resp.ok) { setStatus('Save error: '+await resp.text()); return; }
346	    const r = await resp.json();
347	    setStatus(`✓ Saved → ${r.path}`);
348	  } catch(e) { setStatus('Error: '+e.message); }
349	}
350	
351	async function loadPresets() {
352	  try {
353	    const resp = await fetch('/api/presets');
354	    if (!resp.ok) return;
355	    const presets = await resp.json();
356	    const sel = document.getElementById('presetSelect');
357	    sel.innerHTML = '<option value="">— load preset —</option>'
358	      + presets.map(p => `<option value="${p}">${p}</option>`).join('');
359	  } catch(_) {}
360	}
361	
362	async function loadPreset() {
363	  const name = document.getElementById('presetSelect').value;
364	  if (!name) return;
365	  try {
366	    const resp = await fetch('/api/presets/'+encodeURIComponent(name));
367	    if (!resp.ok) { setStatus('Error loading preset'); return; }
368	    const cfg = await resp.json();
369	    currentConfig = cfg;
370	    renderParams(cfg);
371	    setStatus(`Preset "${name}" loaded`);
372	    if (document.getElementById('autoRescore').checked) rescore();
373	  } catch(e) { setStatus('Error: '+e.message); }
374	}
375	
376	async function savePreset() {
377	  const name = prompt('Preset name (alphanumeric, hyphens):');
378	  if (!name || !name.trim()) return;
379	  const params = collectParams();
380	  try {
381	    const resp = await fetch('/api/presets/'+encodeURIComponent(name.trim()), {
382	      method:'POST', headers:{'Content-Type':'application/json'},
383	      body: JSON.stringify(params)
384	    });
385	    if (!resp.ok) { setStatus('Error saving preset'); return; }
386	    setStatus(`Preset "${name.trim()}" saved`);
387	    await loadPresets();
388	  } catch(e) { setStatus('Error: '+e.message); }
389	}
390	
391	function setStatus(msg) {
392	  document.getElementById('statusMsg').textContent = msg;
393	}
394	
395	async function init() {
396	  try {
397	    const resp = await fetch('/api/config');
398	    if (!resp.ok) { setStatus('Error loading config'); return; }
399	    currentConfig = await resp.json();
400	    renderParams(currentConfig);
401	    await loadPresets();
402	    await rescore();
403	  } catch(e) { setStatus('Error: '+e.message); }
404	}
405	
406	init();
407	</script>
408	</body>
409	</html>
